-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "الأفكار المعاصرة" (afkar-muasira) — تستنفد العنقود بالكامل
-- (8 تصنيفات فرعية من أصل 8، كلها بلا محتوى): الشيوعية، الرأسمالية،
-- العلمانية، الليبرالية، القومية، الإلحاد والمادية، الحداثة وما بعد
-- الحداثة، الفردانية والعولمة.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: مذاهب فكرية معاصرة
-- لمحمد قطب، العدالة الاجتماعية في الإسلام لسيد قطب، العلمانية لسفر
-- الحوالي، الحداثة في ميزان الإسلام لعوض القرني، خطابنا الإسلامي في
-- عصر العولمة ليوسف القرضاوي.
-- كل آية استُشهد بها (القصص:4، التوبة:34، المائدة:50، المائدة:44،
-- الأحزاب:36، الأنبياء:92، الجاثية:24، النساء:46، آل عمران:103)
-- تحقَّقت حرفياً من artifacts/majalis/public/data/quran محلياً عبر حقل
-- numberInSurah قبل الإدراج.
-- كل حديث مستشهَد به (8 أحاديث) متحقَّق حرفياً عبر WebSearch قبل
-- الإدراج: «من قتل دون ماله فهو شهيد، ومن قتل دون دينه فهو شهيد» (أبو
-- داود والترمذي، حسن صحيح، سعيد بن زيد)، «الربا ثلاثة وسبعون بابا،
-- أيسرها مثل أن ينكح الرجل أمه» (ابن ماجه، صححه الألباني، عبدالله بن
-- مسعود)، «لا طاعة لمخلوق في معصية الخالق» (أحمد، إسناده على شرط
-- الشيخين، علي بن أبي طالب)، «ليس منا من دعا إلى عصبية» (مسلم، أبو
-- هريرة)، «ما من مولود إلا يولد على الفطرة» (متفق عليه، أبو هريرة)،
-- «وإياكم ومحدثات الأمور فإن كل بدعة ضلالة» (أبو داود والترمذي، حسن
-- صحيح، العرباض بن سارية)، «مثل المؤمنين في توادهم وتراحمهم وتعاطفهم
-- مثل الجسد» (متفق عليه، النعمان بن بشير). تصنيف العلمانية اكتفى
-- بآيتين (المائدة:50 والمائدة:44) دون حديث لعدم توفر حديث مباشر
-- مناسب دون تكلّف.
-- ملاحظة منهجية: الاستشهاد بآيات كالقصص:4 (طغيان فرعون) والنساء:46
-- (تحريف الكلم) يُستخدم بوصفه تمثيلاً تحليليًا شاع عند علماء الفكر
-- الإسلامي المعاصر لوصف الاستبداد الشمولي وتحريف المعنى، لا بوصفه
-- تفسيرًا مباشرًا للآية بهذه المذاهب الحديثة.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الثمانية عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الشيوعية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9410eab6-087c-48bd-b6cf-0b7e4ce2c326' AND title='الشيوعية ونقضها لتوحيد الله وحق الملكية الخاصة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الشيوعية ونقضها لتوحيد الله وحق الملكية الخاصة', 'تعريف الشيوعية وأصلها المادي الجدلي الملحد، وموقف الإسلام من إلغائها للملكية الفردية وإنكارها وجود الخالق', '9410eab6-087c-48bd-b6cf-0b7e4ce2c326', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأصلها', 'الشيوعية: مذهب اقتصادي واجتماعي يقوم على إلغاء الملكية الخاصة لوسائل الإنتاج وجعلها ملكية جماعية تديرها الدولة، مبني على فلسفة مادية جدلية (ماركسية) تُفسّر التاريخ تفسيرًا اقتصاديًا بحتًا وتُنكر وجود الخالق، وقد تبنّت الأنظمة الشيوعية التاريخية إلحادًا رسميًا واضطهدت أهل الأديان جميعًا. يخالف الإسلام هذا المذهب في أصلين: توحيد الله الذي تنكره الشيوعية، وإقرار الملكية الخاصة المشروعة التي كفلها الإسلام مع تقييدها بالزكاة والتكافل الاجتماعي.', 1),
    (v_lesson, 'evidence', 'خطر الاستبداد الشمولي وحرمة المال', 'استخدم علماء الفكر الإسلامي المعاصر وصف الله لطغيان فرعون واستضعافه الناس مثالاً لخطر الأنظمة الشمولية التي تسيطر على كل مناحي حياة الإنسان، قال تعالى: ﴿إِنَّ فِرْعَوْنَ عَلَا فِي الْأَرْضِ وَجَعَلَ أَهْلَهَا شِيَعًا يَسْتَضْعِفُ طَائِفَةً مِّنْهُمْ﴾ (القصص: 4)، وعن سعيد بن زيد رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ، وَمَنْ قُتِلَ دُونَ دِينِهِ فَهُوَ شَهِيدٌ»، رواه أبو داود والترمذي وقال: حديث حسن صحيح.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مذاهب فكرية معاصرة — محمد قطب (فصل الشيوعية)', 1);
  END IF;

  -- 2) الرأسمالية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='35f11b29-cdd6-40bc-b421-f2903dad5a98' AND title='الرأسمالية وموقف الإسلام من اكتناز المال والربا') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الرأسمالية وموقف الإسلام من اكتناز المال والربا', 'تعريف الرأسمالية واعتمادها على الربا أداة لتنمية رأس المال، وموقف الإسلام المقرّ للملكية الفردية المقيّدة بالزكاة والمحرّم للربا', '35f11b29-cdd6-40bc-b421-f2903dad5a98', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'الرأسمالية: نظام اقتصادي يقوم على الملكية الفردية المطلقة لوسائل الإنتاج وحرية السوق دون قيد شرعي، مع اعتماد الفائدة الربوية أداة أساسية لتمويل الاستثمار وتنمية رأس المال. يقرّ الإسلام الملكية الفردية ويحفظها، لكنه يقيّدها بأحكام الزكاة والتكافل الاجتماعي، ويحرّم الربا تحريمًا قطعيًا بوصفه أداة استغلال تُراكم الثروة عند فئة على حساب الفقراء والمحتاجين.', 1),
    (v_lesson, 'evidence', 'ذم الاكتناز وخطر الربا', 'قال تعالى في ذم من يجمع المال ولا يؤدي حقه: ﴿وَالَّذِينَ يَكْنِزُونَ الذَّهَبَ وَالْفِضَّةَ وَلَا يُنفِقُونَهَا فِي سَبِيلِ اللَّهِ فَبَشِّرْهُم بِعَذَابٍ أَلِيمٍ﴾ (التوبة: 34)، وعن عبد الله بن مسعود رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «الرِّبَا ثَلَاثَةٌ وَسَبْعُونَ بَابًا، أَيْسَرُهَا مِثْلُ أَنْ يَنْكِحَ الرَّجُلُ أُمَّهُ»، رواه ابن ماجه وصححه الألباني.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'العدالة الاجتماعية في الإسلام — سيد قطب', 1);
  END IF;

  -- 3) العلمانية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2e6907a9-8a90-48fb-b95e-83166791c8a8' AND title='العلمانية وموقف الإسلام من فصل الدين عن الحياة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('العلمانية وموقف الإسلام من فصل الدين عن الحياة', 'تعريف العلمانية ونشأتها الأوروبية، وبيان تعارضها مع شمول الإسلام لكل جوانب الحياة تشريعًا وسياسة واقتصادًا', '2e6907a9-8a90-48fb-b95e-83166791c8a8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها ونشأتها', 'العلمانية: فصل الدين عن شؤون الحياة والدولة، بحيث يُحصر الدين في العبادات الفردية ولا يكون له سلطان على التشريع والسياسة والاقتصاد والاجتماع. نشأت في أوروبا نتيجة صراع الكنيسة مع العلم والفلسفة، ونُقلت إلى بلاد المسلمين بوصفها حلاً مستوردًا لا يلائم دينًا شموليًا كالإسلام يحكم كل جوانب حياة الإنسان.', 1),
    (v_lesson, 'evidence', 'شمول حكم الله وذم التحاكم لغيره', 'قال تعالى: ﴿أَفَحُكْمَ الْجَاهِلِيَّةِ يَبْغُونَ وَمَنْ أَحْسَنُ مِنَ اللَّهِ حُكْمًا لِقَوْمٍ يُوقِنُونَ﴾ (المائدة: 50)، وقال تعالى: ﴿وَمَن لَّمْ يَحْكُم بِمَا أَنزَلَ اللَّهُ فَأُولَٰئِكَ هُمُ الْكَافِرُونَ﴾ (المائدة: 44).', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'العلمانية: نشأتها وتطورها وآثارها في الحياة الإسلامية المعاصرة — سفر بن عبد الرحمن الحوالي', 1);
  END IF;

  -- 4) الليبرالية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='89308989-3416-4179-ba10-8fc68a3655aa' AND title='الليبرالية وضابط الحرية الفردية في الإسلام') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الليبرالية وضابط الحرية الفردية في الإسلام', 'تعريف الليبرالية وتقديسها للحرية الفردية المطلقة، وبيان أن الإسلام يقيّد الحرية بحكم الله ورسوله لا بإرادة الفرد وحدها', '89308989-3416-4179-ba10-8fc68a3655aa', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'الليبرالية: فلسفة تقوم على تقديس الحرية الفردية المطلقة في المعتقد والسلوك والقول بأدنى قدر من القيود، وجعل إرادة الفرد مرجعًا في تقرير الحق والباطل والخير والشر. يقرّ الإسلام حرية الاختيار في أصل الإيمان، لكنه لا يجعل الحرية مطلقة بلا ضابط، بل يقيّدها بحكم الله ورسوله في كل ما يتصل بالحلال والحرام، فلا اعتبار لإرادة الفرد إذا صادمت نص الشرع.', 1),
    (v_lesson, 'evidence', 'تقييد الاختيار بحكم الله ورسوله', 'قال تعالى: ﴿وَمَا كَانَ لِمُؤْمِنٍ وَلَا مُؤْمِنَةٍ إِذَا قَضَى اللَّهُ وَرَسُولُهُ أَمْرًا أَن يَكُونَ لَهُمُ الْخِيَرَةُ مِنْ أَمْرِهِمْ﴾ (الأحزاب: 36)، وعن علي بن أبي طالب رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «لَا طَاعَةَ لِمَخْلُوقٍ فِي مَعْصِيَةِ الْخَالِقِ»، رواه أحمد وإسناده على شرط الشيخين.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مذاهب فكرية معاصرة — محمد قطب (فصل الديمقراطية والإنسانية الغربية)', 1);
  END IF;

  -- 5) القومية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='df9a66fa-674b-4cd6-bc8e-383b62f75c4d' AND title='القومية وموقف الإسلام من عصبية الجاهلية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('القومية وموقف الإسلام من عصبية الجاهلية', 'تعريف القومية بوصفها امتدادًا للعصبية الجاهلية، وبيان أن الإسلام جعل رابطة الأخوة الإيمانية فوق كل رابطة عرقية أو قبلية', 'df9a66fa-674b-4cd6-bc8e-383b62f75c4d', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'القومية: مذهب يجعل الرابطة العرقية أو اللغوية أو الجغرافية أساس الولاء والانتماء والتجمع السياسي، بديلاً عن رابطة العقيدة، وهي امتداد لعصبية الجاهلية التي حاربها الإسلام. جعل الإسلام رابطة الأخوة الإيمانية فوق كل رابطة عرقية أو قبلية أو وطنية، فلا فضل لعربي على أعجمي إلا بالتقوى.', 1),
    (v_lesson, 'evidence', 'وحدة الأمة وذم العصبية', 'قال تعالى: ﴿إِنَّ هَٰذِهِ أُمَّتُكُمْ أُمَّةً وَاحِدَةً وَأَنَا رَبُّكُمْ فَاعْبُدُونِ﴾ (الأنبياء: 92)، وعن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «لَيْسَ مِنَّا مَنْ دَعَا إِلَى عَصَبِيَّةٍ، وَلَيْسَ مِنَّا مَنْ قَاتَلَ عَلَى عَصَبِيَّةٍ، وَلَيْسَ مِنَّا مَنْ مَاتَ عَلَى عَصَبِيَّةٍ»، رواه مسلم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مذاهب فكرية معاصرة — محمد قطب (فصل القومية)', 1);
  END IF;

  -- 6) الإلحاد والمادية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8dd2d724-ffdf-450b-9caa-6d6a59797d29' AND title='الإلحاد والمادية ودلالة الفطرة على وجود الخالق') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الإلحاد والمادية ودلالة الفطرة على وجود الخالق', 'تعريف الإلحاد والمادية الفلسفية المنكرة لما وراء المادة، والرد عليهما بدلالة الفطرة التي فطر الله الناس عليها', '8dd2d724-ffdf-450b-9caa-6d6a59797d29', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما', 'الإلحاد: إنكار وجود الله تعالى. والمادية الفلسفية: مذهب يرى أن المادة هي الحقيقة الوحيدة وأن لا وجود لما وراءها من غيب أو خالق أو روح، وأن الكون نشأ صدفة دون خالق مدبر. يرد الإسلام هذا المذهب بدلالة الفطرة التي فطر الله الناس عليها من الإقرار بوجوده، وبأدلة الخلق والنظام الدالة على وجود صانع حكيم.', 1),
    (v_lesson, 'evidence', 'حكاية قول الدهريين والفطرة', 'قال تعالى حاكيًا قول المنكرين للبعث المُسندين الفناء إلى الدهر: ﴿وَقَالُوا مَا هِيَ إِلَّا حَيَاتُنَا الدُّنْيَا نَمُوتُ وَنَحْيَا وَمَا يُهْلِكُنَا إِلَّا الدَّهْرُ وَمَا لَهُم بِذَٰلِكَ مِنْ عِلْمٍ إِنْ هُمْ إِلَّا يَظُنُّونَ﴾ (الجاثية: 24)، وعن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَا مِنْ مَوْلُودٍ إِلَّا يُولَدُ عَلَى الْفِطْرَةِ، فَأَبَوَاهُ يُهَوِّدَانِهِ أَوْ يُنَصِّرَانِهِ أَوْ يُمَجِّسَانِهِ» متفق عليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مذاهب فكرية معاصرة — محمد قطب (فصل الإلحاد)', 1);
  END IF;

  -- 7) الحداثة وما بعد الحداثة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d6605aef-55f1-442b-abeb-e4fea2c93715' AND title='الحداثة وما بعد الحداثة وخطر تحريف الثوابت') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الحداثة وما بعد الحداثة وخطر تحريف الثوابت', 'تعريف الحداثة وما بعد الحداثة وقطيعتهما مع الموروث والثوابت، وتحذير علماء الإسلام من توظيف منهجهما في التعامل مع النصوص الشرعية', 'd6605aef-55f1-442b-abeb-e4fea2c93715', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'الحداثة: تيار فكري وأدبي نشأ في الغرب يقوم على القطيعة مع الموروث والثوابت وتقديس التجديد لذاته، وامتد إلى الأدب العربي بدعوى تفكيك اللغة وتعدد القراءات وزعزعة استقرار المعنى. أما ما بعد الحداثة فتزيد على ذلك بإنكار وجود حقيقة ثابتة أصلاً. حذّر علماء الإسلام من توظيف هذا المنهج في التعامل مع النصوص الشرعية بما يفتح باب تحريف معانيها عن مواضعها الصحيحة.', 1),
    (v_lesson, 'evidence', 'تحريف الكلم والتحذير من محدثات الأمور', 'قال تعالى في وصف من يحرّفون معاني الكلام عن مواضعه الصحيحة: ﴿يُحَرِّفُونَ الْكَلِمَ عَن مَّوَاضِعِهِ﴾ (النساء: 46)، وعن العرباض بن سارية رضي الله عنه أن رسول الله صلى الله عليه وسلم قال في خطبته: «وَإِيَّاكُمْ وَمُحْدَثَاتِ الْأُمُورِ، فَإِنَّ كُلَّ بِدْعَةٍ ضَلَالَةٌ»، رواه أبو داود والترمذي وقال: حديث حسن صحيح.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الحداثة في ميزان الإسلام — عوض بن محمد القرني', 1);
  END IF;

  -- 8) الفردانية والعولمة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='dc74d29a-0e60-4a60-be00-f932193e32c1' AND title='الفردانية والعولمة وأثرهما على وحدة الأمة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الفردانية والعولمة وأثرهما على وحدة الأمة', 'تعريف الفردانية والعولمة وأثرهما في إضعاف الروابط الجماعية، وحث الإسلام على الاعتصام بحبل الله جميعًا وعدم التفرق', 'dc74d29a-0e60-4a60-be00-f932193e32c1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما', 'الفردانية: تضخيم مكانة الفرد ومصلحته الذاتية على حساب الروابط الجماعية كالأسرة والمجتمع والأمة. والعولمة: انتشار نمط ثقافي واقتصادي واحد (غالبًا غربيًا) عبر العالم بفعل تطور الاتصالات والاقتصاد، بما يهدد الخصوصيات الثقافية والدينية للشعوب ويُضعف روابط الأخوة الإيمانية لصالح نزعة فردية استهلاكية معولمة.', 1),
    (v_lesson, 'evidence', 'الاعتصام بحبل الله وترابط الجسد الواحد', 'قال تعالى: ﴿وَاعْتَصِمُوا بِحَبْلِ اللَّهِ جَمِيعًا وَلَا تَفَرَّقُوا﴾ (آل عمران: 103)، وعن النعمان بن بشير رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «مَثَلُ الْمُؤْمِنِينَ فِي تَوَادِّهِمْ وَتَرَاحُمِهِمْ وَتَعَاطُفِهِمْ مَثَلُ الْجَسَدِ إِذَا اشْتَكَى مِنْهُ عُضْوٌ تَدَاعَى لَهُ سَائِرُ الْجَسَدِ بِالسَّهَرِ وَالْحُمَّى» متفق عليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'خطابنا الإسلامي في عصر العولمة — يوسف القرضاوي', 1);
  END IF;

